const payload = $input.first().json.body ?? $input.first().json;
const issue = payload.issue ?? {};
const fields = issue.fields ?? {};

const status = fields.status?.name ?? '';
if (status !== 'In Progress') {
  return [];
}

const summary = fields.summary ?? '';
const descText = JSON.stringify(fields.description ?? '');

// 手動票略過，不觸發 Claude API（2026-07-05 修訂：改讀票面 ExecMode：欄位，不再依賴 summary 裡的 [手動] 字樣，因為新版標題不含執行方式標籤）
const execModeMatch = descText.match(/ExecMode[：:]\s*([^\s"\\]+)/);
const execMode = execModeMatch ? execModeMatch[1] : '';
if (execMode.includes('手動')) {
  return [];
}

const tddMatch = descText.match(/測試命名[：:]\s*`?([^`\n"]+)`?/);
const tddDod = tddMatch ? tddMatch[1].trim() : '';

const slugMatch = descText.match(/Slug[：:]\s*([^\s"\\]+)/);
const slug = slugMatch ? slugMatch[1] : '';

const taskIdMatch = descText.match(/TaskId[：:]\s*[^\s#"\\]+#([^\s#"\\]+)#(T\d+)/);
const sourceFile = taskIdMatch ? taskIdMatch[1] : '';
const taskId = taskIdMatch ? taskIdMatch[2] : '';

return [{
  json: {
    jiraKey: issue.key ?? '',
    summary,
    tddDod,
    slug,
    taskId,
    sourceFile,
    jiraUrl: `https://prostyliu.atlassian.net/browse/${issue.key}`,
    issueId: issue.id ?? '',
  }
}];

const ticket = $('解析票面').first().json;
const taskId = ticket.taskId;
const sourceFile = ticket.sourceFile;

const fileNodeMap = {
  'tasks-backend.md': '讀取 tasks-backend.md',
  'tasks-devops.md': '讀取 tasks-devops.md',
  'tasks-qa.md': '讀取 tasks-qa.md',
};

function extractBlock(content, id) {
  if (!content) return null;
  const startRe = new RegExp('^### ' + id + ' — ', 'm');
  const startMatch = content.match(startRe);
  if (!startMatch) return null;
  const startIdx = startMatch.index;
  const rest = content.slice(startIdx);
  const firstNewline = rest.indexOf('\n');
  const remainder = firstNewline >= 0 ? rest.slice(firstNewline + 1) : '';
  const nextMatch = remainder.match(/\n### T\d+ /);
  const block = nextMatch ? rest.slice(0, firstNewline + 1 + nextMatch.index) : rest;
  return block.trim();
}

if (!taskId) {
  throw new Error('票面缺少 TaskId，無法定位任務區塊（檢查 Jira Description 是否有 TaskId：<slug>#<sourceFile>#<taskId> 這行）');
}
if (!sourceFile || !fileNodeMap[sourceFile]) {
  throw new Error(`票面 TaskId 缺少合法的 sourceFile（收到：${sourceFile}），無法定位是 tasks-backend.md/tasks-devops.md/tasks-qa.md 哪一份，不可用「同編號猜測」避免抓錯任務`);
}

// 2026-07-05 修正：taskId（T01、T02...）是各檔案獨立編號，backend/devops/qa 可能有同編號的不同任務，
// 必須用票面明確指定的 sourceFile 直接讀該檔案，不能依序嘗試三份檔案（會誤抓到第一個符合編號的區塊）。
const content = $(fileNodeMap[sourceFile]).first().json.content;
const block = extractBlock(content, taskId);
if (!block) {
  throw new Error(`在 ${sourceFile} 裡找不到 ${taskId} 對應的任務區塊`);
}

return [{ json: { taskBody: block, sourceFile } }];

const ticket = $('解析票面').first().json;
const specContent = $('讀取 spec').first().json.content ?? '';
const designContent = $('讀取 design').first().json.content ?? '';
const taskBody = $('擷取任務區塊').first().json.taskBody ?? '';
const sourceFile = $('擷取任務區塊').first().json.sourceFile ?? '';

let availableDeps = [];
try {
  const pkgRaw = $('讀取 package.json').first().json.content ?? '{}';
  const pkg = JSON.parse(pkgRaw);
  availableDeps = Object.keys({ ...(pkg.dependencies ?? {}), ...(pkg.devDependencies ?? {}) });
} catch (e) {
  availableDeps = [];
}

const systemPrompt = `你是一位嚴格遵循 TDD 紀律的 TypeScript 後端工程師。
你必須依照以下規範產出程式碼：
- 函式長度上限 50 行
- 所有錯誤處理必須有繁體中文上下文，禁止 silent fail
- 測試命名格式：應該_<預期行為>_當<條件>
- 禁止直接產出業務邏輯，必須先產出測試檔案

目前 package.json 已安裝的依賴（優先使用這些，不要無故引入新套件）：
${availableDeps.join(', ') || '（無）'}

如果任務**必須**使用一個不在上面清單裡的套件才能完成，才可以在輸出裡列出 additional_dependencies，
Agent Runner 會在寫入測試檔前自動執行 npm install。禁止在沒有列出的情況下於程式碼中 import 未安裝的套件。

你的輸出必須是嚴格的 JSON 格式：
{
  "test_file_path": "test/xxx.test.ts",
  "test_file_content": "（完整測試檔案內容）",
  "impl_file_path": "src/xxx.ts",
  "impl_file_content": "（完整業務邏輯內容）",
  "additional_dependencies": ["套件名稱"],
  "commit_message": "feat(backend): [票號] 實作功能描述"
}
"additional_dependencies" 沒有需要時請輸出空陣列 []，不可省略此欄位。`;

const userPrompt = `Jira 票號：${ticket.jiraKey}
任務標題：${ticket.summary}
TDD 完成定義：${ticket.tddDod}

完整任務內容（含依賴與所有驗收條件）：
${taskBody}

規格文件內容：
${specContent}

設計文件內容：
${designContent}

請依照上述規格，產出這張票的測試檔案與業務邏輯實作。`;

return [{ json: { systemPrompt, userPrompt, jiraKey: ticket.jiraKey, jiraUrl: ticket.jiraUrl, issueId: ticket.issueId, summary: ticket.summary, slug: ticket.slug, taskId: ticket.taskId, sourceFile } }];

const item = $input.first().json;
return [{
  json: {
    ...item,
    claudeBody: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 8192,
      system: item.systemPrompt,
      messages: [{ role: 'user', content: item.userPrompt }]
    })
  }
}];

const response = $input.first().json;
const rawText = response.content?.[0]?.text ?? '';

if (response.stop_reason === 'max_tokens') {
  throw new Error('Claude 回應被 max_tokens 截斷，尚未產出完整 JSON。請提高 準備 Claude Body 節點的 max_tokens 設定。回應片段：' + rawText.slice(-300));
}

const jsonMatch = rawText.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('Claude 回應無法解析為 JSON：' + rawText.substring(0, 200));
}

let parsed;
try {
  parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error('Claude 回應 JSON 解析失敗（可能被截斷或格式錯誤）：' + e.message + ' | 回應結尾：' + rawText.slice(-300));
}
// 防禦性修復：Claude 偶爾會漏掉 impl_file_path（尤其在同時要求 additional_dependencies 時），
// 但測試檔一定會 import 實作檔案，路徑資訊其實都在，用這個推斷取代直接失敗重跑。
if (!parsed.impl_file_path && parsed.test_file_content) {
  const importMatch = parsed.test_file_content.match(/from\s+['"](\.\.[^'"]+)['"]/);
  if (importMatch) {
    let inferred = importMatch[1].replace(/^\.\.\//, '');
    if (!/\.[a-zA-Z]+$/.test(inferred)) inferred += '.ts';
    parsed.impl_file_path = inferred;
    parsed._impl_file_path_inferred = true;
  }
}

const required = ['test_file_path', 'test_file_content', 'impl_file_path', 'impl_file_content', 'commit_message'];
const missing = required.filter(k => !parsed[k]);

if (missing.length > 0) {
  throw new Error(`Claude 回應缺少必要欄位：${missing.join(', ')}（impl_file_path 自動推斷也失敗，測試檔內容裡找不到符合的 import 路徑）`);
}

const additionalDependencies = Array.isArray(parsed.additional_dependencies) ? parsed.additional_dependencies.filter(Boolean) : [];

const prev = $('準備 Claude Body').first().json;
return [{
  json: {
    ...parsed,
    additionalDependencies,
    jiraKey: prev.jiraKey,
    jiraUrl: prev.jiraUrl,
    issueId: prev.issueId,
    summary: prev.summary,
    slug: prev.slug,
    taskId: prev.taskId,
    sourceFile: prev.sourceFile,
  }
}];

const item = $('解析回應').first().json;
const basePath = 'D:/06_Workspace/Workspace_GitHub/xu3clayu83ire/alag-addyosmani-demos/awtw-short-url-service-agent';

return [{
  json: {
    ...item,
    body_gitCheckout: JSON.stringify({
      command: 'git checkout main && git pull origin main && git checkout -b feature/' + item.jiraKey,
      cwd: basePath
    }),
    body_writeTest: JSON.stringify({
      filePath: basePath + '/' + item.test_file_path,
      content: item.test_file_content
    }),
    body_runTest: JSON.stringify({
      command: 'npm run test',
      cwd: basePath
    }),
    body_writeImpl: JSON.stringify({
      filePath: basePath + '/' + item.impl_file_path,
      content: item.impl_file_content
    }),
    body_gitCommit: JSON.stringify({
      command: 'git add . && git commit -m ' + JSON.stringify(item.commit_message) + ' && git push origin feature/' + item.jiraKey,
      cwd: basePath
    }),
    body_githubPR: JSON.stringify({
      title: '[' + item.jiraKey + '] ' + item.summary,
      head: 'feature/' + item.jiraKey,
      base: 'main',
      body: '## ASUS 自動產生 PR\n\n- Jira：' + item.jiraUrl + '\n- 由 ASUS Phase 3 自動建立\n\n## TDD 驗證\n- 紅燈確認（測試先 Fail）\n- 綠燈確認（測試全數 Pass）'
    })
  }
}];

const item = $input.first().json;
const output = (item.stdout ?? '') + '\n' + (item.stderr ?? '');

// 2026-07-05 修正：「Failed to load url ../src/xxx」在紅燈階段是正常現象（實作檔案本來就還沒寫），
// 不能一律當環境錯誤。真正的環境錯誤是「找不到的是套件名稱」（不是本地相對路徑）。
function isLocalPath(spec) { return /^[./]/.test((spec || '').trim()); }

const failedToLoadMatch = output.match(/Failed to load url ([^\s(]+)/i);
const cannotFindMatch = output.match(/Cannot find module ['"]?([^'"\s]+)['"]?/i);
const target = failedToLoadMatch?.[1] || cannotFindMatch?.[1];
const isBarePackageSpecifier = Boolean(target) && !isLocalPath(target);

const hardEnvErrorPatterns = [
  /Cannot find package/i,
  /ERR_MODULE_NOT_FOUND/i,
  /SyntaxError/i,
  /ENOENT.*package\.json/i,
];
const hasHardEnvError = hardEnvErrorPatterns.some(re => re.test(output));

if (hasHardEnvError || isBarePackageSpecifier) {
  throw new Error(`測試執行失敗是環境問題，不是有效的 TDD 紅燈（缺少套件或環境錯誤：${target || '未知'}）。輸出片段：${output.slice(0, 500)}`);
}

return [{ json: item }];

const item = $input.first().json;
const output = (item.stdout ?? '') + '\n' + (item.stderr ?? '');

function isLocalPath(spec) { return /^[./]/.test((spec || '').trim()); }

const failedToLoadMatch = output.match(/Failed to load url ([^\s(]+)/i);
const cannotFindMatch = output.match(/Cannot find module ['"]?([^'"\s]+)['"]?/i);
const target = failedToLoadMatch?.[1] || cannotFindMatch?.[1];
const isBarePackageSpecifier = Boolean(target) && !isLocalPath(target);

const hardEnvErrorPatterns = [
  /Cannot find package/i,
  /ERR_MODULE_NOT_FOUND/i,
  /SyntaxError/i,
  /ENOENT.*package\.json/i,
];
const hasHardEnvError = hardEnvErrorPatterns.some(re => re.test(output));

if (hasHardEnvError || isBarePackageSpecifier) {
  throw new Error(`測試執行失敗是環境問題，不是有效的 TDD 綠燈（缺少套件或環境錯誤：${target || '未知'}）。輸出片段：${output.slice(0, 500)}`);
}

return [{ json: item }];

const response = $input.first().json;
const transitions = response.transitions || [];
const target = transitions.find(t =>
  t.name === 'In Review' ||
  t.name === 'Review' ||
  (t.to && t.to.name === 'In Review')
);

if (!target) {
  const names = transitions.map(t => t.name).join(', ');
  throw new Error('找不到 In Review 轉換。可用轉換：' + names);
}

const prev = $('準備所有 Bodies').first().json;
return [{
  json: {
    jiraKey: prev.jiraKey,
    jiraTransitionId: target.id,
    slug: prev.slug,
    taskId: prev.taskId,
    sourceFile: prev.sourceFile,
  }
}];

const taskId = $('解析 Jira Transition').first().json.taskId;
const jiraKey = $('解析 Jira Transition').first().json.jiraKey;
const slug = $('解析 Jira Transition').first().json.slug;
const content = $input.first().json.content ?? '';
const filePath = $input.first().json.filePath;

const headerRegex = new RegExp('(### ' + taskId + ' — .+?)⬜(.*)$', 'm');
if (!headerRegex.test(content)) {
  throw new Error(`找不到 ${taskId} 對應的 ⬜ 標頭，可能已經是 ✅ 或格式跑掉，需要人工確認 ${filePath}`);
}

// 票號註記已在開票階段（T15 回填任務票號）寫入，這裡只需要把圖示改成 ✅，不可重複加註票號
const updated = content.replace(headerRegex, (match, before, after) => {
  return before + '✅' + after;
});

return [{ json: { filePath, content: updated, taskId, jiraKey, slug } }];
